/**
 * Remove overlap de sufixo/prefixo entre duas strings para reduzir duplicações de chunks.
 */
function mergeTextWithOverlap(baseText: string, incomingText: string): { merged: string; removedChars: number } {
  const base = baseText.trim();
  const incoming = incomingText.trim();

  if (!base) {
    return { merged: incoming, removedChars: 0 };
  }

  if (!incoming) {
    return { merged: base, removedChars: 0 };
  }

  const normalizedBase = base.toLowerCase();
  const normalizedIncoming = incoming.toLowerCase();
  const maxOverlap = Math.min(normalizedBase.length, normalizedIncoming.length, 180);
  let overlapLength = 0;

  for (let size = 8; size <= maxOverlap; size += 1) {
    const suffix = normalizedBase.slice(-size);
    const prefix = normalizedIncoming.slice(0, size);
    if (suffix === prefix) {
      overlapLength = size;
    }
  }

  if (overlapLength === 0) {
    return {
      merged: `${base} ${incoming}`.trim(),
      removedChars: 0
    };
  }

  return {
    merged: `${base}${incoming.slice(overlapLength)}`.trim(),
    removedChars: overlapLength
  };
}

