  /**
   * Converte blob de áudio para base64 para transporte por IPC.
   */
  async function blobToBase64(blob: Blob): Promise<string> {
    const buffer = await blob.arrayBuffer();
    const bytes = new Uint8Array(buffer);
    let binary = "";

    for (let index = 0; index < bytes.length; index += 1) {
      binary += String.fromCharCode(bytes[index]);
    }

    return globalThis.btoa(binary);
  }

  /**
   * Estima energia RMS do áudio para VAD simples baseado em limiar.
   */
  async function calculateAudioRms(blob: Blob): Promise<number> {
    const AudioContextClass = globalThis.AudioContext || (globalThis as { webkitAudioContext?: typeof AudioContext }).webkitAudioContext;
    if (!AudioContextClass) {
      return 1;
    }

    const context = new AudioContextClass();
    try {
      const arrayBuffer = await blob.arrayBuffer();
      const decoded = await context.decodeAudioData(arrayBuffer);
      const channelData = decoded.getChannelData(0);

      if (channelData.length === 0) {
        return 0;
      }

      let sumSquares = 0;
      for (let index = 0; index < channelData.length; index += 1) {
        const sample = channelData[index];
        sumSquares += sample * sample;
      }

      return Math.sqrt(sumSquares / channelData.length);
    } finally {
      await context.close();
    }
  }

  /**
   * Aplica janela deslizante para decidir se há atividade de voz suficiente.
   */
  function evaluateVadWindow(rms: number): VadDecision {
    const normalizedWindow = Math.max(2, Math.min(8, vadWindowSize));
    const nextScores = [...vadScoresRef.current, rms].slice(-normalizedWindow);
    vadScoresRef.current = nextScores;
    setVadRecentScores(nextScores);

    const activeFrames = nextScores.filter((score) => score >= vadThresholdRms).length;
    const minFramesForSpeech = Math.max(1, Math.ceil(nextScores.length / 2));
    const hasVoiceActivity = activeFrames >= minFramesForSpeech;

    setVadStatus(
      `RMS atual ${rms.toFixed(4)} | ativos ${activeFrames}/${nextScores.length} | limiar ${vadThresholdRms.toFixed(4)}`
    );

    return {
      rms,
      activeFrames,
      frames: nextScores.length,
      hasVoiceActivity
    };
  }

  /**
   * Executa uma captura única de áudio e envia para transcrição.
   */
  async function recordSingleAudioChunk(source: "manual" | "auto", maxDurationMs: number): Promise<void> {
    if (activeRecorderRef.current && activeRecorderRef.current.state !== "inactive") {
      setAudioCaptureStatus("Aguardando gravacao atual terminar...");
      return;
    }

    try {
      const audioConstraint = selectedAudioInputDeviceId
        ? { deviceId: { exact: selectedAudioInputDeviceId } }
        : true;

      const stream = await globalThis.navigator.mediaDevices.getUserMedia({ audio: audioConstraint });
      activeStreamRef.current = stream;

      const recorder = new MediaRecorder(stream, { mimeType: "audio/webm" });
      activeRecorderRef.current = recorder;
      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (event) => {
        if (event.data && event.data.size > 0) {
          chunks.push(event.data);
        }
      };

      recorder.onerror = (event) => {
        setAudioCaptureStatus(`Erro no recorder: ${event.error?.message || "desconhecido"}`);
      };

      recorder.onstop = async () => {
        try {
          stream.getTracks().forEach((track) => track.stop());
          activeStreamRef.current = null;

          if (chunks.length === 0) {
            setAudioCaptureStatus("Nenhum audio coletado no intervalo.");
            return;
          }

          const audioBlob = new Blob(chunks, { type: "audio/webm" });
          const rms = await calculateAudioRms(audioBlob);
          const vadDecision = evaluateVadWindow(rms);

          if (!vadDecision.hasVoiceActivity) {
            setAudioCaptureStatus(
              `Silencio dominante detectado (${vadDecision.activeFrames}/${vadDecision.frames}); chunk descartado.`
            );
            setAudioCaptureHint("Ajuste limiar/janela do VAD se sua voz estiver baixa ou distante do microfone.");
            return;
          }

          const chunkBase64 = await blobToBase64(audioBlob);
          const transcription = await window.desktopApi.transcribeAudioChunk({
            sessionId,
            chunkBase64,
            language
          });

          let removedOverlapChars = 0;
          let dedupedChunkText = transcription.text;

          setAudioConsolidatedText((current) => {
            const merged = mergeTextWithOverlap(current, transcription.text);
            removedOverlapChars = merged.removedChars;
            dedupedChunkText = transcription.text.trim() && merged.removedChars > 0
              ? transcription.text.slice(merged.removedChars).trim() || transcription.text
              : transcription.text;
            return merged.merged;
          });

          setAudioDedupeStatus(
            removedOverlapChars > 0
              ? `Overlap removido: ${removedOverlapChars} caractere(s) no ultimo chunk.`
              : "Sem overlap relevante no ultimo chunk."
          );

          setAudioTranscripts((current) => [
            {
              id: globalThis.crypto.randomUUID(),
              source,
              isFinal: transcription.isFinal,
              text: dedupedChunkText,
              createdAtIso: new Date().toISOString()
            },
            ...current
          ].slice(0, 20));

          setAudioCaptureStatus(
            source === "manual"
              ? "Gravacao manual concluida e enviada para transcricao."
              : "Ciclo automatico concluido e enviado para transcricao."
          );
          setAudioCaptureHint(
            `VAD aprovou o chunk com RMS ${vadDecision.rms.toFixed(4)} (${vadDecision.activeFrames}/${vadDecision.frames} frames ativos).`
          );
        } catch (error) {
          const message = error instanceof Error ? error.message : "Erro desconhecido";
          setAudioCaptureStatus(`Falha na transcricao: ${message}`);
          setAudioCaptureHint(
            "No Windows, valide permissao de microfone e se outro aplicativo nao monopolizou o dispositivo."
          );
        } finally {
          activeRecorderRef.current = null;
          if (source === "manual") {
            setIsManualRecording(false);
          }
        }
      };

      recorder.start();
      if (source === "manual") {
        setIsManualRecording(true);
        setAudioCaptureStatus("Gravando manualmente...");
      } else {
        setAudioCaptureStatus("Gravando ciclo automatico...");
      }

      globalThis.setTimeout(() => {
        if (recorder.state !== "inactive") {
          recorder.stop();
        }
      }, maxDurationMs);
    } catch (error) {
      const message = error instanceof Error ? error.message : "Erro desconhecido";
      setAudioCaptureStatus(`Falha ao iniciar gravacao: ${message}`);
      setAudioCaptureHint(
        "No Windows, habilite acesso ao microfone em Configuracoes > Privacidade e seguranca > Microfone."
      );
      setIsManualRecording(false);
    }
  }

  /**
   * Alterna gravação manual (atalho Ctrl+D também disponível).
   */
  async function handleManualRecordToggle(): Promise<void> {
    if (isManualRecording && activeRecorderRef.current && activeRecorderRef.current.state !== "inactive") {
      activeRecorderRef.current.stop();
      setAudioCaptureStatus("Encerrando gravacao manual...");
      return;
    }

    await recordSingleAudioChunk("manual", 8000);
  }

  /**
   * Alterna modo automático por intervalo configurável (10-20s).
   */
  function handleAutoRecordToggle(): void {
    if (isAutoRecordingEnabled) {
      setIsAutoRecordingEnabled(false);
      if (autoRecordTimerRef.current !== null) {
        globalThis.clearInterval(autoRecordTimerRef.current);
        autoRecordTimerRef.current = null;
      }
      setAudioCaptureStatus("Modo automatico desativado.");
      return;
    }

    const clamped = Math.max(10, Math.min(20, autoRecordIntervalSec));
    setAutoRecordIntervalSec(clamped);
    setIsAutoRecordingEnabled(true);
    setAudioCaptureStatus(`Modo automatico ativo a cada ${clamped}s.`);

    autoRecordTimerRef.current = globalThis.setInterval(() => {
      void recordSingleAudioChunk("auto", 6000);
    }, clamped * 1000);
  }

